mapper.select:
/* CourtSttcMapper.getCourtSttcList */
SELECT TO_CHAR(TO_DATE(REGST_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS REGST_DT, TOTAL, TOTAL_RG, SUM_RG, LC_RG, NC_RG, CC_RG, RP_RG, DP_RG, ETC_RG, SUM_RG_END, IMM_RG_END, DC_RG_END, TOTAL_BR, SUM_BR, BR_BR, ETC_BR, SUM_BR_END, IMM_BR_END, DC_BR_END, TOTAL_ENT, SUM_ENT, SUM_ENT_END, REGST_ID, TO_CHAR(REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM, RVISN_ID, TO_CHAR(RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM FROM MSP_COURT_RCV_STTC
WHERE REGST_DT BETWEEN #{strtDt} AND #{endDt}
ORDER BY REGST_DT

/* CourtSttcMapper.getCourtSttcListByExcel */ SELECT TO_CHAR(TO_DATE(REGST_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS REGST_DT, TOTAL, TOTAL_RG, SUM_RG, LC_RG, NC_RG, CC_RG, RP_RG, DP_RG, ETC_RG, SUM_RG_END, IMM_RG_END, DC_RG_END, TOTAL_BR, SUM_BR, BR_BR, ETC_BR, SUM_BR_END, IMM_BR_END, DC_BR_END, TOTAL_ENT, SUM_ENT, SUM_ENT_END, REGST_ID, TO_CHAR(REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM, RVISN_ID, TO_CHAR(RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM FROM MSP_COURT_RCV_STTC
WHERE REGST_DT BETWEEN #{strtDt} AND #{endDt}
ORDER BY REGST_DT
